## Шаг 3. Подключаем React Query для серверных данных (и связываем с UI-фильтрами)
Теперь список грузим по `filters` из Zustand.

```ts
// src/features/orders/api/ordersApi.ts
export async function fetchOrders(params: { status: string; search: string }) {
  const qs = new URLSearchParams(params as any).toString();
  const res = await fetch(`/api/orders?${qs}`, { cache: "no-store" });
  if (!res.ok) throw new Error("Failed to fetch orders");
  return res.json() as Promise<{ items: { id: string; title: string }[] }>;
}
```

Хук:

```ts
// src/features/orders/api/useOrdersQuery.ts
import { useQuery } from "@tanstack/react-query";
import { fetchOrders } from "./ordersApi";

export function useOrdersQuery(filters: { status: string; search: string }) {
  return useQuery({
    queryKey: ["orders", filters], // важно: стабильные ключи
    queryFn: () => fetchOrders(filters),
    staleTime: 10_000,
    refetchInterval: 30_000, // polling только для этого набора
    // enabled: true/false по необходимости
  });
}
```

И компонент:

```tsx
"use client";

import { useOrdersUiStore } from "../ui/useOrdersUiStore";
import { useOrdersQuery } from "../api/useOrdersQuery";

export function OrdersList() {
  const filters = useOrdersUiStore((s) => s.filters);

  const { data, isLoading } = useOrdersQuery(filters);

  const items = data?.items ?? [];
  return (
    <div>
      {isLoading ? "Loading..." : null}
      {items.map((it) => (
        <div key={it.id}>{it.title}</div>
      ))}
    </div>
  );
}
```

Теперь:
- UI-фильтры управляются Zustand’ом
- список и polling — React Query
- нет пропов “filters вниз на 5 уровней”

