## 2) React Query: запрос orders + polling, привязанный к filters (через queryKey)

### API helper (преобразуем Date → числа/строку)
Чтобы `queryKey` был стабильным и вы не зависели от ссылок Date-объектов:

```ts
// src/features/orders/api/ordersApi.ts
export async function fetchOrders(args: {
  startMs: number;
  endMs: number;
  category: string;
}) {
  const { startMs, endMs, category } = args;

  const res = await fetch(
    `/api/orders?start=${startMs}&end=${endMs}&cat=${encodeURIComponent(category)}`
  );
  if (!res.ok) throw new Error("Failed to fetch orders");
  return res.json() as Promise<Order[]>;
}
```

### Query hook

```ts
// src/features/orders/api/useOrdersQuery.ts
import { useQuery } from "@tanstack/react-query";
import { fetchOrders } from "./ordersApi";

export function useOrdersQuery(params: {
  startMs: number;
  endMs: number;
  category: string;
}) {
  return useQuery({
    queryKey: ["orders", params], // params простые числа/строки -> стабильные ключи
    queryFn: () => fetchOrders(params),
    refetchInterval: 30_000, // polling именно для этого набора данных
    // staleTime: 10_000, // опционально
  });
}
```

