## 2) Единое создание AuthContext для GraphQL (Apollo context)

### Функция factory (используется и для GraphQL)
```ts
// src/graphql/auth-context.factory.ts
import { verifyJwt } from '../auth/verify-jwt';
import { AuthContext } from '../auth/auth-context';
import { randomUUID } from 'crypto';

type JwtPayload = { sub: string; tenantId: string; roles?: string[] };

export async function authContextFactory({ req }: { req: any }): Promise<AuthContext> {
  const requestId = req?.headers?.['x-request-id']?.toString() ?? randomUUID();

  const header = req?.headers?.authorization as string | undefined;
  const token = header?.startsWith('Bearer ') ? header.slice('Bearer '.length) : null;
  if (!token) {
    // В зависимости от политики: можно бросать 401 или возвращать “guest”
    throw new Error('UNAUTHENTICATED');
  }

  const payload: JwtPayload = await verifyJwt(token);

  return {
    userId: payload.sub,
    tenantId: payload.tenantId,
    roles: payload.roles ?? [],
    requestId,
  };
}
```

### Подключение Apollo Server в Nest
```ts
// src/app.module.ts (фрагмент)
import { ApolloDriver, ApolloDriverConfig } from '@nestjs/apollo';
import { GraphQLModule } from '@nestjs/graphql';
import { authContextFactory } from './graphql/auth-context.factory';

GraphQLModule.forRoot<ApolloDriverConfig>({
  driver: ApolloDriver,
  autoSchemaFile: true,
  context: async ({ req }) => {
    // Единый способ создать AuthContext
    const authContext = await authContextFactory({ req });
    return { authContext };
  },
});
```

> Теперь `context.authContext` будет доступен директивам/резолверам.

